### 2.3 DTO 정의

```kotlin
// 위치: domain/user/dto/FollowUserDto.kt
data class FollowUserDto(
    val userId: String,
    val name: String,
    val profileImageUrl: String?,
    val isVerified: Boolean,
    val updatedAt: LocalDateTime,
    var isFollowing: Boolean = false, // 현재 사용자 관점에서
    var followerCount: Long = 0,      // 해당 사용자의 팔로워 수
)

@QueryProjection
data class FollowUserDto(
    val userId: String,
    val name: String,
    val profileImageUrl: String?,
    val isVerified: Boolean,
    val updatedAt: LocalDateTime,
)
```

---

### 2.4 Service 레이어

```kotlin
// 위치: user-service/src/main/kotlin/service/FollowService.kt
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val userRepository: UserRepository,
    private val redisTemplate: RedisTemplate<String, String>,
) {
    companion object {
        const val FOLLOWER_COUNT_CACHE_PREFIX = "follower:count:"
        const val FOLLOWING_COUNT_CACHE_PREFIX = "following:count:"
        const val CACHE_DURATION_SECONDS = 3600L
    }

    @Transactional(readOnly = true)
    fun getFollowers(
        userId: String,
        pageable: Pageable
    ): Page<FollowUserDto> {
        val page = followRepository.findFollowersWithDetails(userId, pageable)

        // 각 팔로워의 추가 정보 조회 (필요시)
        page.content.forEach { dto ->
            dto.isFollowing = checkIfCurrentUserFollows(dto.userId) // 개선: 배치 조회 필요
        }

        return page
    }

    @Transactional(readOnly = true)
    fun getFollowing(
        userId: String,
        pageable: Pageable
    ): Page<FollowUserDto> {
        val page = followRepository.findFollowingWithDetails(userId, pageable)

        page.content.forEach { dto ->
            dto.followerCount = getFollowerCount(dto.userId)
        }

        return page
    }

    @Transactional
    fun follow(followerId: String, followingId: String) {
        val follower = userRepository.findById(followerId).orElseThrow()
        val following = userRepository.findById(followingId).orElseThrow()

        if (followRepository.isFollowing(followerId, followingId)) {
            throw AlreadyFollowingException("Already following")
        }

        val follow = FollowEntity(
            follower = follower,
            following = following
        )
        followRepository.save(follow)

        // 캐시 무효화
        invalidateFollowerCount(followingId)
    }

    @Transactional(readOnly = true)
    fun getFollowerCount(userId: String): Long {
        val cacheKey = "$FOLLOWER_COUNT_CACHE_PREFIX$userId"

        return redisTemplate.opsForValue().get(cacheKey)?.toLong()
            ?: followRepository.countFollowers(userId).also { count ->
                redisTemplate.opsForValue().set(
                    cacheKey,
                    count.toString(),
                    CACHE_DURATION_SECONDS,
                    TimeUnit.SECONDS
                )
            }
    }

    private fun invalidateFollowerCount(userId: String) {
        redisTemplate.delete("$FOLLOWER_COUNT_CACHE_PREFIX$userId")
    }
}
```

