### 2.5 gRPC 레이어

```kotlin
// 위치: protobuf/src/main/proto/follow.proto
syntax = "proto3";

package com.maum.follow;

message GetFollowersRequest {
    string user_id = 1;
    int32 page = 2;
    int32 size = 3;
}

message FollowUserResponse {
    string user_id = 1;
    string name = 2;
    string profile_image_url = 3;
    bool is_verified = 4;
    int64 updated_at = 5;
    bool is_following = 6;
    int64 follower_count = 7;
}

message GetFollowersResponse {
    repeated FollowUserResponse users = 1;
    int64 total = 2;
    int32 page = 3;
    int32 size = 4;
}

service FollowService {
    rpc GetFollowers(GetFollowersRequest) returns (GetFollowersResponse);
    rpc GetFollowing(GetFollowersRequest) returns (GetFollowersResponse);
}
```

```kotlin
// 위치: user-service/src/main/kotlin/controller/FollowGrpcService.kt
@GrpcService
class FollowGrpcService(
    private val followService: FollowService,
) : FollowServiceGrpc.FollowServiceImplBase() {

    override fun getFollowers(
        request: GetFollowersRequest,
        responseObserver: StreamObserver<GetFollowersResponse>
    ) {
        try {
            val pageable = PageRequest.of(request.page, request.size)
            val page = followService.getFollowers(request.userId, pageable)

            val response = GetFollowersResponse.newBuilder()
                .addAllUsers(page.content.map { it.toProtoResponse() })
                .setTotal(page.totalElements)
                .setPage(request.page)
                .setSize(request.size)
                .build()

            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }
}
```

