### 2.6 GraphQL 레이어

```graphql
# 위치: graphql/src/main/resources/graphql/follow.graphql
type User {
    id: ID!
    name: String!
    profileImageUrl: String
    isVerified: Boolean!
    followerCount: Int!
    followingCount: Int!
    isFollowing: Boolean!
}

type FollowList {
    users: [User!]!
    total: Int!
    pageInfo: PageInfo!
}

type Query {
    followers(userId: ID!, first: Int = 20, after: String): FollowList!
    following(userId: ID!, first: Int = 20, after: String): FollowList!
}

type Mutation {
    follow(userId: ID!): User!
    unfollow(userId: ID!): User!
}
```

```kotlin
// 위치: graphql/src/main/kotlin/controller/FollowGraphQLController.kt
@Controller
@RequestMapping("/graphql")
class FollowGraphQLController(
    @GrpcClient("user-service")
    private val followServiceStub: FollowServiceGrpc.FollowServiceBlockingStub,
) {

    @QueryMapping
    @PreAuthorize("isAuthenticated()")
    fun followers(
        @Argument userId: String,
        @Argument first: Int = 20,
        @Argument(name = "after") cursor: String? = null
    ): FollowList {
        try {
            val page = decodeCursor(cursor)
            val request = GetFollowersRequest.newBuilder()
                .setUserId(userId)
                .setPage(page)
                .setSize(first)
                .build()

            val response = followServiceStub.getFollowers(request)

            return FollowList(
                users = response.usersList.map { it.toDomain() },
                total = response.total.toInt(),
                pageInfo = PageInfo(
                    hasNextPage = response.page * response.size < response.total,
                    endCursor = encodeCursor(response.page + 1)
                )
            )
        } catch (e: StatusRuntimeException) {
            throw GraphQLException(e.status.code.toString(), e.status.description)
        }
    }
}
```

