## 6. 캐싱 전략

```kotlin
// 위치: user-service/src/main/kotlin/config/CacheConfig.kt

@Configuration
@EnableCaching
class CacheConfig {

    @Bean
    fun cacheManager(): CacheManager {
        return RedisCacheManager.create(
            RedisConnectionFactory().connection!!.connectionFactory!!
        ).apply {
            setDefaultExpiration(3600) // 1시간
        }
    }
}

// Service에서 사용
@Service
class FollowService(
    private val followRepository: FollowRepository
) {

    @Cacheable(
        value = "follower-count",
        key = "#userId",
        unless = "#result == 0"
    )
    fun getFollowerCount(userId: String): Long {
        return followRepository.countFollowers(userId)
    }

    @CacheEvict(value = "follower-count", key = "#followingId")
    fun follow(followerId: String, followingId: String) {
        // follow 로직
    }
}
```

