## 8. 테스트 가이드

```kotlin
// 위치: user-service/src/test/kotlin/service/FollowServiceTest.kt

@DataJpaTest
@Import(JPAQueryFactory::class)
class FollowRepositoryTest {

    @Test
    fun `팔로워 조회 시 N+1 문제 없음`() {
        // Given
        val follower1 = userRepository.save(UserEntity(id = "user1"))
        val follower2 = userRepository.save(UserEntity(id = "user2"))
        val following = userRepository.save(UserEntity(id = "user3"))

        followRepository.saveAll(listOf(
            FollowEntity(follower = follower1, following = following),
            FollowEntity(follower = follower2, following = following)
        ))

        // When
        val queryCount = QueryCountHolder.reset()
        val result = followRepository.findFollowersWithDetails(following.id, PageRequest.of(0, 20))

        // Then
        assertThat(queryCount).isEqualTo(1) // 단 1개의 쿼리만 발생
        assertThat(result.content).hasSize(2)
    }
}
