#### QueryDSL 구현 (성능 최적화)

```kotlin
// 위치: domain/user/repository/impl/CustomFollowRepositoryImpl.kt
@Component
class CustomFollowRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : CustomFollowRepository {

    // 문제점 1: N+1 없이 팔로워 조회 (WITH JOIN FETCH)
    override fun findFollowersWithDetails(
        userId: String,
        pageable: Pageable
    ): Page<FollowUserDto> {
        val follow = QFollowEntity.followEntity
        val follower = QUserEntity.userEntity

        // 서브쿼리로 페이지네이션 처리
        val ids = queryFactory
            .select(follow.id)
            .from(follow)
            .where(
                follow.following.id.eq(userId),
                follow.deletedAt.isNull
            )
            .orderBy(follow.createdAt.desc())
            .offset(pageable.offset)
            .limit(pageable.pageSize.toLong())
            .fetch()

        // 페이지 크기 초과 확인
        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(
                follow.following.id.eq(userId),
                follow.deletedAt.isNull
            )
            .fetchOne() ?: 0L

        // 실제 데이터 조회 (JOIN FETCH로 N+1 방지)
        val result = queryFactory
            .select(QFollowUserDto(
                follower.id,
                follower.name,
                follower.profileImageUrl,
                follower.isVerified,
                follower.updatedAt
            ))
            .from(follow)
            .innerJoin(follow.follower, follower)
            .where(
                follow.following.id.eq(userId),
                follow.deletedAt.isNull,
                follow.id.`in`(ids)
            )
            .orderBy(follow.createdAt.desc())
            .fetch()

        return PageImpl(result, pageable, total)
    }

    // 문제점 2: 존재 여부 확인 최적화
    override fun isFollowing(
        followerId: String,
        followingId: String
    ): Boolean {
        val follow = QFollowEntity.followEntity

        return queryFactory
            .selectOne()
            .from(follow)
            .where(
                follow.follower.id.eq(followerId),
                follow.following.id.eq(followingId),
                follow.deletedAt.isNull
            )
            .fetchFirst() != null
    }

    // 문제점 3: COUNT 쿼리 분리 (복잡한 경우 캐싱 검토)
    override fun countFollowers(userId: String): Long {
        val follow = QFollowEntity.followEntity

        return queryFactory
            .select(follow.count())
            .from(follow)
            .where(
                follow.following.id.eq(userId),
                follow.deletedAt.isNull
            )
            .fetchOne() ?: 0L
    }
}
```

