### 4.3 페이지네이션 최적화 (Keyset Pagination)

```kotlin
// 고급 최적화: Keyset Pagination (커서 기반)
override fun findFollowersKeyset(
    userId: String,
    lastId: String? = null,
    pageSize: Int = 20
): List<FollowUserDto> {
    val follow = QFollowEntity.followEntity

    val query = queryFactory
        .select(QFollowUserDto(
            follow.follower.id,
            follow.follower.name,
            follow.follower.profileImageUrl,
            follow.follower.isVerified,
            follow.follower.updatedAt
        ))
        .from(follow)
        .innerJoin(follow.follower)
        .where(
            follow.following.id.eq(userId),
            follow.deletedAt.isNull
        )
        .orderBy(follow.createdAt.desc(), follow.id.desc())

    // 커서 후속 페이지
    if (lastId != null) {
        val lastCreatedAt = queryFactory
            .select(follow.createdAt)
            .from(follow)
            .where(follow.id.eq(lastId))
            .fetchOne()

        query.where(
            follow.createdAt.loe(lastCreatedAt),
            follow.id.ne(lastId)
        )
    }

    return query.limit((pageSize + 1).toLong()).fetch()
}
```

### 4.4 배치 처리 최적화

```kotlin
// 문제: 여러 사용자의 팔로워 수를 각각 조회
// Service에서 루프로 countFollowers() 호출 → N번의 COUNT 쿼리

// 해결책: 배치 조회
override fun countFollowersBatch(userIds: List<String>): Map<String, Long> {
    val follow = QFollowEntity.followEntity

    return queryFactory
        .select(follow.following.id, follow.count())
        .from(follow)
        .where(
            follow.following.id.`in`(userIds),
            follow.deletedAt.isNull
        )
        .groupBy(follow.following.id)
        .fetch()
        .associate { tuple ->
            tuple.get(follow.following.id) to tuple.get(follow.count())
        }
}
```

