```kotlin
package com.maum.backend.service.follow

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.repository.follow.FollowRepository
import org.springframework.data.domain.Slice
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
@Transactional(readOnly = true)
class FollowService(
    private val followRepository: FollowRepository
) {

    /**
     * 팔로워 목록 조회 (커서 기반 페이지네이션)
     */
    fun getFollowers(
        followingId: String,
        lastId: String? = null,
        lastCreatedAt: Long? = null,
        limit: Int = 20
    ): Slice<FollowEntity> {
        return followRepository.findFollowersByFollowingId(
            followingId = followingId,
            lastId = lastId,
            lastCreatedAt = lastCreatedAt,
            limit = limit
        )
    }

    /**
     * 팔로잉 목록 조회 (커서 기반 페이지네이션)
     */
    fun getFollowings(
        followerId: String,
        lastId: String? = null,
        lastCreatedAt: Long? = null,
        limit: Int = 20
    ): Slice<FollowEntity> {
        return followRepository.findFollowingsByFollowerId(
            followerId = followerId,
            lastId = lastId,
            lastCreatedAt = lastCreatedAt,
            limit = limit
        )
    }

    /**
     * 특정 사용자를 팔로우하는지 확인 (N+1 방지)
     */
    fun isFollowing(followerId: String, followingId: String): Boolean {
        return followRepository.findActiveFollow(followerId, followingId) != null
    }

    /**
     * 여러 사용자를 팔로우하는지 일괄 확인
     */
    fun getFollowingStatus(followerId: String, followingIds: List<String>): Map<String, Boolean> {
        val relationships = followRepository.findFollowRelationships(followerId, followingIds)
        return followingIds.associateWith { relationships.containsKey(it) }
    }

    /**
     * 팔로워/팔로잉 수 조회
     */
    fun getFollowStats(userId: String): FollowStats {
        return FollowStats(
            followersCount = followRepository.countFollowers(userId),
            followingsCount = followRepository.countFollowings(userId)
        )
    }

    /**
     * 여러 사용자의 팔로워 수 일괄 조회
     */
    fun getFollowersCountMap(userIds: List<String>): Map<String, Long> {
        val result = followRepository.countFollowersByFollowingIds(userIds)
        return result.associate { (userId, count) ->
            userId as String to (count as Long)
        }.also { map ->
            // 데이터가 없는 사용자는 0으로 설정
            userIds.forEach { userId ->
                map.getOrDefault(userId, 0L)
            }
        }
    }

    /**
     * 팔로우 추가
     */
    @Transactional
    fun createFollow(followerId: String, followingId: String): FollowEntity {
        require(followerId != followingId) { "자기 자신을 팔로우할 수 없습니다." }
        require(!followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            "이미 팔로우 중입니다."
        }

        val follow = FollowEntity(
            followerId = followerId,
            followingId = followingId,
            status = FollowEntity.STATUS_APPROVED
        )
        return followRepository.save(follow)
    }

    /**
     * 팔로우 취소
     */
    @Transactional
    fun deleteFollow(followerId: String, followingId: String) {
        val follow = followRepository.findActiveFollow(followerId, followingId)
            ?: throw IllegalArgumentException("팔로우 관계를 찾을 수 없습니다.")
        follow.softDelete()
        followRepository.save(follow)
    }

    data class FollowStats(
        val followersCount: Long,
        val followingsCount: Long
    )
}
