        Index(
            name = "idx_follow_status_created",
            columnList = "status,created_at",
            unique = false
        ),
        // 소프트 딜리트 처리
        Index(
            name = "idx_follow_deleted_at",
            columnList = "deleted_at",
            unique = false
        )
    ]
)
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    @Column(length = 36)
    val id: String = "",

    // 팔로우를 시작한 사용자
    @Column(name = "follower_id", nullable = false, length = 36)
    val followerId: String,

    // 팔로우되는 사용자
    @Column(name = "following_id", nullable = false, length = 36)
    val followingId: String,

    // 팔로우 상태 (0: 대기, 1: 승인, 2: 거절, 3: 차단)
    @Column(name = "status", nullable = false)
    var status: Int = 1,

    // 생성 시간 (정렬용)
    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    val createdAt: LocalDateTime = LocalDateTime.now(),

    // 수정 시간
    @LastModifiedDate
    @Column(columnDefinition = "datetime(3)", nullable = false)
    var updatedAt: LocalDateTime = LocalDateTime.now(),

    // 소프트 딜리트
    @Column(columnDefinition = "datetime(3)")
    var deletedAt: LocalDateTime? = null,

    // 메모
    @Column(columnDefinition = "text")
    var memo: String? = null
) {
    // 팔로우 상태 상수
    companion object {
        const val STATUS_PENDING = 0
        const val STATUS_APPROVED = 1
        const val STATUS_REJECTED = 2
        const val STATUS_BLOCKED = 3
    }

    // 활성 팔로우인지 확인
    fun isActive(): Boolean = status == STATUS_APPROVED && deletedAt == null

    // 소프트 딜리트
    fun softDelete() {
        deletedAt = LocalDateTime.now()
        status = STATUS_BLOCKED
    }

    // 팔로우 승인
    fun approve() {
        status = STATUS_APPROVED
        updatedAt = LocalDateTime.now()
    }

    // 팔로우 거절
    fun reject() {
        status = STATUS_REJECTED
        updatedAt = LocalDateTime.now()
    }
}
