### 4. FollowRepositoryImpl (QueryDSL 구현)

**파일: `/private/tmp/claude-eval-v4-20260227-215256/name-only/domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepositoryImpl.kt`**

```kotlin
package com.maum.backend.repository.follow

import com.maum.backend.entity.follow.FollowEntity
import com.querydsl.core.BooleanBuilder
import com.querydsl.jpa.impl.JPAQueryFactory
import org.springframework.data.domain.Slice
import org.springframework.data.domain.SliceImpl
import org.springframework.stereotype.Repository
import java.time.LocalDateTime
import java.time.ZoneId

@Repository
class FollowRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : FollowRepositoryCustom {

    private val follow = com.maum.backend.entity.follow.QFollowEntity.followEntity

    /**
     * 팔로워 목록 조회 (커서 기반 페이지네이션)
     * 
     * 성능 최적화:
     * - 복합 인덱스 활용: (following_id, created_at)
     * - JOIN FETCH로 User 정보 미리 로드 (선택사항)
     * - created_at 역순 정렬로 최신 팔로우 먼저 표시
     * - limit + 1 조회로 hasNext 판단
     */
    override fun findFollowersByFollowingId(
        followingId: String,
        lastId: String?,
        lastCreatedAt: Long?,
        limit: Int
    ): Slice<FollowEntity> {
        val lastCreatedAtDateTime = lastCreatedAt?.let {
            LocalDateTime.ofInstant(
                java.time.Instant.ofEpochMilli(it),
                ZoneId.systemDefault()
            )
        }

        val query = queryFactory
            .selectFrom(follow)
            .where(
                follow.followingId.eq(followingId)
                    .and(follow.status.eq(FollowEntity.STATUS_APPROVED))
                    .and(follow.deletedAt.isNull)
            )

        // 커서 조건 추가 (최신순 정렬을 위해 <를 사용)
        if (lastCreatedAtDateTime != null && lastId != null) {
            query.where(
                BooleanBuilder()
                    .or(follow.createdAt.lt(lastCreatedAtDateTime))
                    .or(
                        follow.createdAt.eq(lastCreatedAtDateTime)
                            .and(follow.id.lt(lastId))
                    )
            )
        }

        val results = query
            .orderBy(follow.createdAt.desc(), follow.id.desc())
            .limit((limit + 1).toLong())
            .fetch()

        val hasNext = results.size > limit
        val content = if (hasNext) results.dropLast(1) else results

        return SliceImpl(content, limit, hasNext)
    }

    /**
     * 팔로잉 목록 조회 (커서 기반 페이지네이션)
     * 
     * 성능 최적화:
     * - 복합 인덱스 활용: (follower_id, created_at)
     * - created_at 역순 정렬
     */
    override fun findFollowingsByFollowerId(
        followerId: String,
        lastId: String?,
        lastCreatedAt: Long?,
        limit: Int
    ): Slice<FollowEntity> {
        val lastCreatedAtDateTime = lastCreatedAt?.let {
            LocalDateTime.ofInstant(
                java.time.Instant.ofEpochMilli(it),
                ZoneId.systemDefault()
            )
        }

        val query = queryFactory
            .selectFrom(follow)
            .where(
                follow.followerId.eq(followerId)
                    .and(follow.status.eq(FollowEntity.STATUS_APPROVED))
                    .and(follow.deletedAt.isNull)
            )

        if (lastCreatedAtDateTime != null && lastId != null) {
            query.where(
                BooleanBuilder()
                    .or(follow.createdAt.lt(lastCreatedAtDateTime))
                    .or(
                        follow.createdAt.eq(lastCreatedAtDateTime)
                            .and(follow.id.lt(lastId))
                    )
            )
        }

        val results = query
            .orderBy(follow.createdAt.desc(), follow.id.desc())
            .limit((limit + 1).toLong())
            .fetch()

        val hasNext = results.size > limit
        val content = if (hasNext) results.dropLast(1) else results

        return SliceImpl(content, limit, hasNext)
    }

    /**
     * 사용자들의 팔로우 관계 일괄 조회 (N+1 방지)
     * 
     * 사용 사례: 여러 사용자가 팔로우했는지 한 번에 확인
     * SELECT * FROM follow 
     * WHERE follower_id = ? AND following_id IN (?, ?, ...)
     */
    override fun findFollowRelationships(
        followerId: String,
        followingIds: List<String>
    ): Map<String, FollowEntity> {
        if (followingIds.isEmpty()) return emptyMap()

        return queryFactory
            .selectFrom(follow)
            .where(
                follow.followerId.eq(followerId)
                    .and(follow.followingId.`in`(followingIds))
                    .and(follow.status.eq(FollowEntity.STATUS_APPROVED))
                    .and(follow.deletedAt.isNull)
            )
            .fetch()
            .associateBy { it.followingId }
    }

    /**
     * 여러 사용자의 팔로워 목록 일괄 조회
     * 
     * 사용 사례: 피드에서 여러 사용자의 팔로워 샘플 조회
     * 각 사용자별로 최신 팔로워들을 limit 개수만큼 조회
     */
    override fun findFollowersByFollowingIds(
        followingIds: List<String>,
        limit: Int
    ): Map<String, List<FollowEntity>> {
        if (followingIds.isEmpty()) return emptyMap()

        // 모든 데이터를 조회 후 메모리에서 그룹핑
        val allFollows = queryFactory
            .selectFrom(follow)
            .where(
                follow.followingId.`in`(followingIds)
                    .and(follow.status.eq(FollowEntity.STATUS_APPROVED))
                    .and(follow.deletedAt.isNull)
            )
            .orderBy(follow.createdAt.desc())
            .fetch()

        return followingIds.associateWith { followingId ->
            allFollows
                .filter { it.followingId == followingId }
                .take(limit)
        }
    }
}
