    INDEX `idx_follow_following_created` (`following_id`, `created_at`),

    -- 중복 팔로우 방지 및 팔로우 상태 조회
    UNIQUE INDEX `idx_follow_follower_following` (`follower_id`, `following_id`),

    -- 팔로우 상태 기반 조회
    INDEX `idx_follow_status_created` (`status`, `created_at`),

    -- 소프트 딜리트 관리
    INDEX `idx_follow_deleted_at` (`deleted_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
COMMENT='사용자 팔로우 관계 테이블';
