package com.maum.backend.entity.follow

import jakarta.persistence.*
import org.hibernate.annotations.GenericGenerator
import org.springframework.data.annotation.CreatedDate
import org.springframework.data.jpa.domain.support.AuditingEntityListener
import java.time.LocalDateTime

/**
 * 팔로우 관계 엔티티
 * catalog: maum, 단방향 관계만 사용
 */
@Entity
@Table(
    catalog = "maum",
    name = "follow",
    uniqueConstraints = [UniqueConstraint(columnNames = ["follower_id", "followee_id"])],
    indexes = [
        Index(name = "idx_follower_id", columnList = "follower_id"),
        Index(name = "idx_followee_id", columnList = "followee_id")
    ]
)
@EntityListeners(AuditingEntityListener::class)
class FollowEntity(

    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    // 팔로우 하는 사람
    @Column(name = "follower_id", nullable = false, length = 36)
    val followerId: String,

    // 팔로우 받는 사람
    @Column(name = "followee_id", nullable = false, length = 36)
    val followeeId: String,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),
)
