package com.maum.backend.repository.follow

import com.maum.backend.entity.follow.FollowEntity
import org.springframework.data.jpa.repository.JpaRepository
import org.springframework.data.jpa.repository.Query

interface FollowRepository : JpaRepository<FollowEntity, String> {

    // 팔로워 수 조회 (커버링 인덱스 활용: idx_followee_id)
    fun countByFolloweeId(followeeId: String): Long

    // 팔로잉 수 조회 (커버링 인덱스 활용: idx_follower_id)
    fun countByFollowerId(followerId: String): Long

    // 팔로우 관계 존재 여부
    fun existsByFollowerIdAndFolloweeId(followerId: String, followeeId: String): Boolean

    // 팔로우 관계 삭제
    fun deleteByFollowerIdAndFolloweeId(followerId: String, followeeId: String)

    // 팔로워 목록 페이징 (목록은 캐싱 없이 직접 DB 조회)
    @Query(
        "SELECT f FROM FollowEntity f WHERE f.followeeId = :followeeId ORDER BY f.createdAt DESC",
        countQuery = "SELECT COUNT(f) FROM FollowEntity f WHERE f.followeeId = :followeeId"
    )
    fun findFollowersByFolloweeId(
        followeeId: String,
        pageable: org.springframework.data.domain.Pageable
    ): org.springframework.data.domain.Page<FollowEntity>

    // 팔로잉 목록 페이징
    @Query(
        "SELECT f FROM FollowEntity f WHERE f.followerId = :followerId ORDER BY f.createdAt DESC",
        countQuery = "SELECT COUNT(f) FROM FollowEntity f WHERE f.followerId = :followerId"
    )
    fun findFollowingsByFollowerId(
        followerId: String,
        pageable: org.springframework.data.domain.Pageable
    ): org.springframework.data.domain.Page<FollowEntity>
}
