### 4-3. Cache Config

파일: `follow-service/src/main/kotlin/com/maum/backend/follow/config/FollowCacheConfig.kt`

```kotlin
package com.maum.backend.follow.config

import org.springframework.cache.CacheManager
import org.springframework.context.annotation.Bean
import org.springframework.context.annotation.Configuration
import org.springframework.data.redis.cache.RedisCacheConfiguration
import org.springframework.data.redis.cache.RedisCacheManager
import org.springframework.data.redis.connection.RedisConnectionFactory
import org.springframework.data.redis.serializer.GenericJackson2JsonRedisSerializer
import org.springframework.data.redis.serializer.RedisSerializationContext
import org.springframework.data.redis.serializer.StringRedisSerializer
import java.time.Duration

@Configuration
class FollowCacheConfig {

    companion object {
        // 캐시 이름 상수 - FollowService에서 동일하게 참조
        const val FOLLOWER_COUNT_CACHE = "follow:follower-count"
        const val FOLLOWING_COUNT_CACHE = "follow:following-count"

        // TTL 상수
        val FOLLOWER_COUNT_TTL: Duration = Duration.ofMinutes(10)
        val FOLLOWING_COUNT_TTL: Duration = Duration.ofMinutes(5)
    }

    @Bean
    fun followCacheManager(connectionFactory: RedisConnectionFactory): CacheManager {
        val defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
            .serializeKeysWith(
                RedisSerializationContext.SerializationPair.fromSerializer(StringRedisSerializer())
            )
            .serializeValuesWith(
                RedisSerializationContext.SerializationPair.fromSerializer(
                    GenericJackson2JsonRedisSerializer()
                )
            )
            .disableCachingNullValues()

        val cacheConfigurations = mapOf(
            // 팔로워 수: 타인 프로필 조회 빈도 높음, 10분 허용
            FOLLOWER_COUNT_CACHE to defaultConfig.entryTtl(FOLLOWER_COUNT_TTL),
            // 팔로잉 수: 본인 화면에서도 노출, 5분으로 단축
            FOLLOWING_COUNT_CACHE to defaultConfig.entryTtl(FOLLOWING_COUNT_TTL),
        )

        return RedisCacheManager.builder(connectionFactory)
            .cacheDefaults(defaultConfig)
            .withInitialCacheConfigurations(cacheConfigurations)
            .build()
    }
}
```

### 4-4. FollowService (핵심)

파일: `follow-service/src/main/kotlin/com/maum/backend/follow/service/FollowService.kt`

```kotlin
package com.maum.backend.follow.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.follow.config.FollowCacheConfig
import com.maum.backend.follow.monitoring.FollowCacheMetrics
import com.maum.backend.repository.follow.FollowRepository
import org.slf4j.LoggerFactory
import org.springframework.cache.annotation.CacheEvict
import org.springframework.cache.annotation.Cacheable
import org.springframework.cache.annotation.Caching
import org.springframework.data.domain.Page
import org.springframework.data.domain.Pageable
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val followCacheMetrics: FollowCacheMetrics,
) {

    private val log = LoggerFactory.getLogger(javaClass)

    // ------------------------------------------------------------------
    // 카운트 조회 (캐싱 적용)
    // ------------------------------------------------------------------

    /**
     * 팔로워 수 조회
     * 캐시 키: "follow:follower-count::{userId}"
     * TTL: 10분 (FollowCacheConfig 참조)
     * Cache-Aside 패턴: 미스 시 DB 조회 후 자동 캐싱
     */
    @Cacheable(
        cacheManager = "followCacheManager",
        cacheNames = [FollowCacheConfig.FOLLOWER_COUNT_CACHE],
        key = "#userId",
    )
    @Transactional(readOnly = true)
    fun countFollowers(userId: String): Long {
        log.debug("캐시 미스 - DB에서 팔로워 수 조회: userId={}", userId)
        followCacheMetrics.recordMiss(FollowCacheConfig.FOLLOWER_COUNT_CACHE)
        return followRepository.countByFolloweeId(userId)
    }

    /**
     * 팔로잉 수 조회
     * 캐시 키: "follow:following-count::{userId}"
     * TTL: 5분
     */
    @Cacheable(
        cacheManager = "followCacheManager",
        cacheNames = [FollowCacheConfig.FOLLOWING_COUNT_CACHE],
        key = "#userId",
    )
    @Transactional(readOnly = true)
    fun countFollowing(userId: String): Long {
        log.debug("캐시 미스 - DB에서 팔로잉 수 조회: userId={}", userId)
        followCacheMetrics.recordMiss(FollowCacheConfig.FOLLOWING_COUNT_CACHE)
        return followRepository.countByFollowerId(userId)
    }

    // ------------------------------------------------------------------
    // 목록 조회 (캐싱 없음 - 페이징 특성상 DB 직접 조회)
    // ------------------------------------------------------------------

    @Transactional(readOnly = true)
    fun getFollowers(userId: String, pageable: Pageable): Page<FollowEntity> {
        return followRepository.findFollowersByFolloweeId(userId, pageable)
    }

    @Transactional(readOnly = true)
    fun getFollowings(userId: String, pageable: Pageable): Page<FollowEntity> {
        return followRepository.findFollowingsByFollowerId(userId, pageable)
    }

    // ------------------------------------------------------------------
    // 팔로우 / 언팔로우 (캐시 무효화 포함)
    // ------------------------------------------------------------------

    /**
     * 팔로우
     * 무효화 대상:
     *   - followeeId의 followerCount (팔로워 수 증가)
     *   - followerId의 followingCount (팔로잉 수 증가)
     *
     * @Caching으로 두 캐시를 원자적으로 동시 무효화
     */
    @Caching(
        evict = [
            CacheEvict(
                cacheManager = "followCacheManager",
                cacheNames = [FollowCacheConfig.FOLLOWER_COUNT_CACHE],
                key = "#followeeId"         // 팔로우 받는 사람의 팔로워 수 무효화
            ),
            CacheEvict(
                cacheManager = "followCacheManager",
                cacheNames = [FollowCacheConfig.FOLLOWING_COUNT_CACHE],
                key = "#followerId"         // 팔로우 하는 사람의 팔로잉 수 무효화
            ),
        ]
    )
    @Transactional
    fun follow(followerId: String, followeeId: String) {
        require(followerId != followeeId) { "자기 자신을 팔로우할 수 없습니다." }

        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            log.warn("이미 팔로우 관계 존재: followerId={}, followeeId={}", followerId, followeeId)
            return
        }

        followRepository.save(
            FollowEntity(followerId = followerId, followeeId = followeeId)
        )

        log.info("팔로우 완료 - followerId={}, followeeId={}", followerId, followeeId)
        followCacheMetrics.recordEvict(FollowCacheConfig.FOLLOWER_COUNT_CACHE)
        followCacheMetrics.recordEvict(FollowCacheConfig.FOLLOWING_COUNT_CACHE)
    }

    /**
     * 언팔로우
     * follow와 동일한 두 캐시 무효화
     */
    @Caching(
        evict = [
            CacheEvict(
                cacheManager = "followCacheManager",
                cacheNames = [FollowCacheConfig.FOLLOWER_COUNT_CACHE],
                key = "#followeeId"
            ),
            CacheEvict(
                cacheManager = "followCacheManager",
                cacheNames = [FollowCacheConfig.FOLLOWING_COUNT_CACHE],
                key = "#followerId"
            ),
        ]
    )
    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            log.warn("팔로우 관계 없음: followerId={}, followeeId={}", followerId, followeeId)
            return
        }

        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)

        log.info("언팔로우 완료 - followerId={}, followeeId={}", followerId, followeeId)
        followCacheMetrics.recordEvict(FollowCacheConfig.FOLLOWER_COUNT_CACHE)
        followCacheMetrics.recordEvict(FollowCacheConfig.FOLLOWING_COUNT_CACHE)
    }

    // ------------------------------------------------------------------
    // 팔로우 여부 확인 (캐싱 없음 - 정확도 필요)
    // ------------------------------------------------------------------

    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean {
        return followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)
    }
}
```

### 4-5. 성능 모니터링

파일: `follow-service/src/main/kotlin/com/maum/backend/follow/monitoring/FollowCacheMetrics.kt`

```kotlin
package com.maum.backend.follow.monitoring

import io.micrometer.core.instrument.Counter
import io.micrometer.core.instrument.MeterRegistry
import io.micrometer.core.instrument.Tags
import org.springframework.stereotype.Component

/**
 * 캐시 히트율 측정 컴포넌트
 *
 * Micrometer -> Prometheus -> Grafana 파이프라인 가정
 * 메트릭 이름 패턴: maum_follow_cache_{hit|miss|evict}_total{cache_name}
 */
@Component
class FollowCacheMetrics(private val meterRegistry: MeterRegistry) {

    // ------------------------------------------------------------------
    // 캐시 히트 카운터 (Spring Cache의 @Cacheable이 실제 반환한 경우)
    // @Cacheable 자체는 hit를 직접 노출하지 않으므로 miss 기록 후
    // hit = 전체 호출 - miss 로 Grafana에서 계산
    // ------------------------------------------------------------------

    fun recordMiss(cacheName: String) {
        counter("miss", cacheName).increment()
    }

    fun recordHit(cacheName: String) {
        counter("hit", cacheName).increment()
    }

    fun recordEvict(cacheName: String) {
        counter("evict", cacheName).increment()
    }

    private fun counter(type: String, cacheName: String): Counter {
        return Counter.builder("maum.follow.cache.$type")
            .tags(Tags.of("cache_name", cacheName))
            .description("Follow 캐시 $type 횟수")
            .register(meterRegistry)
    }
}
```

파일: `follow-service/src/main/kotlin/com/maum/backend/follow/monitoring/FollowCacheAspect.kt`

```kotlin
package com.maum.backend.follow.monitoring

import com.maum.backend.follow.config.FollowCacheConfig
import org.aspectj.lang.ProceedingJoinPoint
import org.aspectj.lang.annotation.Around
import org.aspectj.lang.annotation.Aspect
import org.springframework.cache.CacheManager
import org.springframework.stereotype.Component

/**
 * 캐시 히트/미스를 AOP로 측정
 *
 * @Cacheable 호출 전 캐시 존재 여부를 확인하여
 * hit/miss를 정확하게 Micrometer에 기록한다.
 */
@Aspect
@Component
class FollowCacheAspect(
    private val followCacheManager: CacheManager,
    private val followCacheMetrics: FollowCacheMetrics,
) {

    @Around(
        "execution(* com.maum.backend.follow.service.FollowService.countFollowers(..)) && args(userId)"
    )
    fun aroundCountFollowers(pjp: ProceedingJoinPoint, userId: String): Any? {
        return measureCacheHit(pjp, FollowCacheConfig.FOLLOWER_COUNT_CACHE, userId)
    }

    @Around(
        "execution(* com.maum.backend.follow.service.FollowService.countFollowing(..)) && args(userId)"
    )
    fun aroundCountFollowing(pjp: ProceedingJoinPoint, userId: String): Any? {
        return measureCacheHit(pjp, FollowCacheConfig.FOLLOWING_COUNT_CACHE, userId)
    }

    private fun measureCacheHit(
        pjp: ProceedingJoinPoint,
        cacheName: String,
        key: String,
    ): Any? {
        val cache = followCacheManager.getCache(cacheName)
        val cached = cache?.get(key)

        if (cached != null) {
            followCacheMetrics.recordHit(cacheName)
        }
        // miss는 FollowService 내부에서 recordMiss() 직접 호출

        return pjp.proceed()
    }
}
```

